\begin{align*}
2(2u+4v) &= 2(-8),\\
4u+8v &= -16.\tag{3}.
\end{align*}
Now, subtract equation (1) from equation (3):
\begin{align*}
(4u+8v)-(4u-5v) &= -16-23,\\
13v &= -39,\\
v &= -3.
\end{align*}
